insert into productos (id, nombre, descripcion, precio, categoria, imagen, instagram_url, activo) values
('DaeEsVLuPmX', 'Collar Dorado Miel', 'Un diseño que se ha convertido en uno de los grandes favoritos de nuestra marca. Este espectacular collar de tres vueltas, elaborado en madera natural con detalles de inspiración étnica y topes grabados artesanalmente, destaca por su diseño exclusivo y su increíble ligereza.', 85000, 'collares-perlas', '/productos/collares-perlas/DaeEsVLuPmX.png', 'https://www.instagram.com/etnika_modaydiseno/p/DaeEsVLuPmX/', true),
('DZ_kkoTuYd-', 'Collar Multicapa Perla Nácar', 'Cerramos esta jornada con una pieza que refleja el arte de lo auténtico. Este exclusivo collar asimétrico, elaborado en madera y cuidadosamente diseñado, combina formas y detalles que le aportan un estilo elegante y diferente. Una creación pensada para mujeres que disfrutan destacar con accesorios únicos y llenos de personalidad.', 95000, 'collares-multicapa', '/productos/collares-multicapa/DZ_kkoTuYd-.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ_kkoTuYd-/', true),
('DZ_hJU4uS9J', 'Collar Perla y Ámbar', 'Elegancia que trasciende tendencias. Este exclusivo collar ha sido diseñado en madera, combinando esferas color café con acabado tipo cristal y delicados topes inspirados en el arte Wayuu, que aportan un toque artesanal y auténtico.', 85000, 'collares-perlas', '/productos/collares-perlas/DZ_hJU4uS9J.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ_hJU4uS9J/', true),
('DZ_dHhLOK6_', 'Collar Multicapa Marfil', 'Inspirado en la riqueza de las creaciones artesanales, presentamos este hermoso collar tipo pectoral, elaborado con una armoniosa combinación de maderas, formas y texturas que evocan la esencia ancestral de nuestras raíces.', 95000, 'collares-multicapa', '/productos/collares-multicapa/DZ_dHhLOK6_.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ_dHhLOK6_/', true),
('DZ_PgA5OyvS', 'Collar Multicapa Ámbar Intenso', 'Inspirada en la riqueza de las creaciones artesanales, presentamos este hermoso collar tipo pectoral, elaborado con una armoniosa combinación de maderas, formas y texturas que evocan la esencia ancestral de nuestras raíces pacífico.', 95000, 'collares-multicapa', '/productos/collares-multicapa/DZ_PgA5OyvS.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ_PgA5OyvS/', true),
('DZ-wfvZveW6', 'Collar Perla Dorada', 'Collar de cuatro vueltas en tono madera beige, elaborado con cuencas cuidadosamente seleccionadas y detalles inspirados en la tradición Wayuu a través de sus topes grabados, que aportan una esencia artesanal única.', 85000, 'collares-perlas', '/productos/collares-perlas/DZ-wfvZveW6.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ-wfvZveW6/', true),
('DZ-wWlbv8Mu', 'Collar Multicapa Perla Clásica', 'Collar de tres vueltas en tonos blanco hueso, elaborado con cuencas cuidadosamente seleccionadas y detalles inspirados en la tradición Wayuu a través de sus topes grabados, que aportan una esencia artesanal única.', 95000, 'collares-multicapa', '/productos/collares-multicapa/DZ-wWlbv8Mu.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ-wWlbv8Mu/', true),
('DZ-uezlEc_j', 'Collar Fiesta con Cruz', 'Dulces, vibrantes y llenos de personalidad. Nuestra cápsula de collares Candy combina perlas tornasoladas en tonos pastel y colores vibrantes para crear accesorios únicos, modernos y llenos de encanto.', 85000, 'collares-perlas', '/productos/collares-perlas/DZ-uezlEc_j.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ-uezlEc_j/', true),
('DZ-IEZxupdo', 'Collar Largo con Dije Ámbar', 'Elegancia que se nota en cada detalle. Este exclusivo collar combina hebras tipo cuero, piezas en madera y hermosos dijes marmoleados que aportan movimiento y sofisticación. Un accesorio versátil y auténtico, creado para elevar tus looks con un toque de distinción, estilo y personalidad. Me encantó EleganciaNatural', 80000, 'collares-largos', '/productos/collares-largos/DZ-IEZxupdo.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ-IEZxupdo/', true),
('DZ-HKbYO7Ns', 'Collar Multicolor con Cruz', 'Dulces, vibrantes y llenos de personalidad. Nuestra cápsula de collares Candy combina perlas tornasoladas en tonos pastel y colores vibrantes para crear accesorios únicos, modernos y llenos de encanto. Diseñados para mujeres que aman expresar su estilo con frescura, alegría y autenticidad.', 85000, 'collares-perlas', '/productos/collares-perlas/DZ-HKbYO7Ns.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZ-HKbYO7Ns/', true),
('DZt4lLDufSY', 'Collar Noche Dorada', 'Collar en madera con diseño de piedras marmolizadas en tonos amarillo y café Una pieza elegida por una mujer muy linda. Está pieza mañana le llegará a sus manos para acompañarla y resaltar la elegancia que la caracteriza. Cada detalle de este collar fue creado para ella que aprecia lo auténtico, lo natural y que transmita glamour.', 85000, 'collares-perlas', '/productos/collares-perlas/DZt4lLDufSY.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZt4lLDufSY/', true),
('DZt21SNuwNt', 'Collar Ébano con Aros', 'Este collar sí que tiene presencia. Es una pieza que no pasa desapercibida. Su imponente diseño, el tamaño perfecto de sus piedras y el elegante detalle en bronce con baño de oro de 24K lo convierten en un accesorio capaz de atraer todas las miradas. Una creación para ella que disfruta destacar con estilo, autenticidad y sofisticación.', 85000, 'collares-perlas', '/productos/collares-perlas/DZt21SNuwNt.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZt21SNuwNt/', true),
('DZt2DW2ubXJ', 'Collar Rosa con Cruz', 'Collar Rosa en piedra natural Una pieza auténtica, creada para una mujer especial que ama la moda, lo auténtico y los detalles que transmitan su personalidad. Su delicado diseño y la belleza única de cada piedra lo convierten en un accesorio lleno de elegancia.', 85000, 'collares-perlas', '/productos/collares-perlas/DZt2DW2ubXJ.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZt2DW2ubXJ/', true),
('DZc6d6LuiFk', 'Collar Turquesa con Dije', 'Maxicollar doble cuenca con dije, diseñado en piedra fósil color turquesa, un accesorio que eleva cualquier outfit', 85000, 'collares-perlas', '/productos/collares-perlas/DZc6d6LuiFk.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZc6d6LuiFk/', true),
('DZRQFYOOCx3', 'Collar Rojo Medallón', 'Collar de esferas en resina rojo, con maxi dije protagonista que resalta su acabado único y sofisticado. Una pieza elegante, poderosa y versátil, perfecta para elevar desde un look casual hasta un outfit más sofisticado. Siéntete auténtica, moderna y única con accesorios que marcan la diferencia.', 85000, 'collares-perlas', '/productos/collares-perlas/DZRQFYOOCx3.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZRQFYOOCx3/', true),
('DZRPu_4uP4t', 'Collar Esmeralda Medallón', 'Collar artesanal en madera con esferas maxi en tonos verde y café, acompañado de un dije protagonista que resalta su acabado único y sofisticado. Una pieza elegante, poderosa y versátil, perfecta para elevar desde un look casual hasta un outfit más sofisticado. Siéntete auténtica, moderna y única con accesorios que marcan la diferencia.', 85000, 'collares-perlas', '/productos/collares-perlas/DZRPu_4uP4t.png', 'https://www.instagram.com/etnika_modaydiseno/p/DZRPu_4uP4t/', true),
